%%%===================================================================
%%% OCEL2 Parsing Functions
%%%===================================================================

%% @doc Parse OCEL2 JSON format into native handle
%% @param Json OCEL2 JSON string
%% @return {ok, ParseResult} | {error, Reason}
parse_ocel2_json(Json) when is_list(Json) ->
    case process_mining_bridge_l2:pm_parse_ocel2_json(Json) of
        #parse_result{handle = Handle, error = undefined} ->
            {ok, Handle};
        #parse_result{error = Error} ->
            {error, Error}
    end.

%%%===================================================================
%%% Log Information Functions
%%%===================================================================

%% @doc Get event count from loaded OCEL log
%% @param LogHandle OCEL log handle
%% @return integer() number of events
log_event_count(LogHandle) when is_integer(LogHandle) ->
    process_mining_bridge_l2:pm_log_event_count(LogHandle).

%% @doc Retrieve all events from loaded OCEL log
%% @param LogHandle OCEL log handle
%% @return #ocel_events_result{}
log_get_events(LogHandle) when is_integer(LogHandle) ->
    process_mining_bridge_l2:pm_log_get_events(LogHandle).

%% @doc Get object count from loaded OCEL log
%% @param LogHandle OCEL log handle
%% @return integer() number of objects
log_object_count(LogHandle) when is_integer(LogHandle) ->
    process_mining_bridge_l2:pm_log_object_count(LogHandle).

%% @doc Retrieve all objects from loaded OCEL log
%% @param LogHandle OCEL log handle
%% @return #ocel_objects_result{}
log_get_objects(LogHandle) when is_integer(LogHandle) ->
    process_mining_bridge_l2:pm_log_get_objects(LogHandle).

