%% @doc Free OCEL log handle to release native memory
%% @param LogHandle OCEL log handle to free
log_free(LogHandle) when is_integer(LogHandle) ->
    process_mining_bridge_l2:pm_log_free(LogHandle).

%% @doc Free OCEL events result to release native memory
%% @param EventsResult OCEL events result to free
events_free(EventsResult) when is_record(EventsResult, ocel_events_result) ->
    process_mining_bridge_l2:pm_events_free(EventsResult).

%% @doc Free OCEL objects result to release native memory
%% @param ObjectsResult OCEL objects result to free
objects_free(ObjectsResult) when is_record(ObjectsResult, ocel_objects_result) ->
