%%%===================================================================
%%% Helper Functions
%%%===================================================================

%% @doc Load native library if not already loaded
ensure_loaded() ->
    case erlang:get(native_loaded) of
        true ->
            ok;
        _ ->
            case process_mining_bridge_l2:start() of
                ok ->
                    erlang:put(native_loaded, true),
                    ok;
                {error, Reason} ->
                    error({native_library_failed, Reason})
            end
    end.

%% @doc Validate all capabilities are available
validate_capabilities() ->
    Capabilities = [
        parse_ocel2_json,
        log_event_count,
        log_get_events,
        log_object_count,
        log_get_objects,
        discover_dfg,
        check_conformance,
        log_free,
        events_free,
        objects_free,
        dfg_free,
        error_free
    ],

    lists:foreach(fun(Cap) ->
        case erlang:function_exported(?MODULE, Cap, 1) of
            true ->
                ok;
            false ->
                error({capability_missing, Cap})
        end
    end, Capabilities).